mapper.select:
/* ptnrInsrMapper.getInsrMemberList */

SELECT  A.CONTRACT_NUM
        , A.CUST_NM
        , A.CTN
        , A.RATE_CD
        , A.RATE_NM
        , A.INSR_CD
        , FN_GET_CODENM('CMN0246', A.INSR_CD) AS INSR_NM
        , A.EFCT_STRT_DT
        , A.EFCT_END_DT
        , A.PYMN_YN
        , A.BIRTH_DT
        , A.MINOR_AGENT_NM
        , A.MINOR_AGENT_TEL
        , A.OPEN_AGNT_CD
        , A.OPEN_AGNT_NM
        , FN_GET_AGE('X', A.CONTRACT_NUM) AS AGE
FROM    MSP_PARTNER_DONGBU_01 A
WHERE   1 = 1

	AND     A.SEND_DT = #{searchBaseDate}


	AND     A.STAT_CD = #{searchInsrStatus}


	AND     A.PYMN_YN = #{searchPymnYn}


	AND     (CASE WHEN A.SUB_STATUS = 'C' OR A.PYMN_YN = 'N' THEN 'N' ELSE 'Y' END) = #{searchEfctYn}


	AND     A.RATE_CD = #{searchRateCd}




			AND     UPPER(A.CUST_NM) = #{searchVal}


			AND     A.CONTRACT_NUM = #{searchVal}


			AND     A.CTN = #{searchVal}




	AND     A.INSR_CD = #{searchInsrCd}

ORDER BY A.CUST_NM

/* ptnrInsrMapper.selectDongbuRate */ SELECT DISTINCT A.RATE_CD AS value , B.RATE_NM AS text FROM MSP_PARTNER_RATE_MST A , MSP_RATE_MST B WHERE A.RATE_CD = B.RATE_CD AND A.USE_YN = 'Y'
AND A.PARTNER_ID = #{parnterId}
ORDER BY 2
